    <script>
        $(function() {
            // Material Select Initialization
            $('.mdb-select').materialSelect();

            dataTable.getData();
        });

        const dataTable = {
            table: null,
            filter: null,
            init: function() {
                dataTable.table = $(""#data-table"").DataTable({
                    processing: true,
                    serverSide: true,
                    ajax: {
                        url: ""/Product/GetProductByCategory"",
                        type: ""POST"",
                        data: function(d) {
                            d.filters = dataTable.filter;
                        }
                    },
                    columns:
                    [
                        { data: ""ProductName"" },
                        {
                            data: ""Stock"",
                            ""render"": function(data, type, row, meta) {
                                return data > 0 ? `<a class=""blue-text"" href=""");
                WriteLiteral(@"/Product/StockDetails/${row.ProductId}"">${data}</a>` : data;
                            }
                        },
                        { data: ""Warranty"" },
                        { data: ""Description"" }
                    ],
