            const categoryName = document.getElementById('categoryName');
            categoryName.textContent = parentId.options[parentId.selectedIndex].text;

            dataTable.filter = [{ Field: ""ProductCatalogId"", Value: categoryId, Operand: ""=="" }];
            dataTable.getData();
        }
    </script>
